// Build Today suggestions from the LIVE project store. Returns [] for a
// fresh/empty project (the UI then shows an empty state) — never the
// static demo prompts. Sections: prompts / quests / threads / untouched.
function buildTodaySuggestions() {
  var B = typeof window !== "undefined" && window.LoomwrightBackend;
  if (!B?.EntityService) return [];
  var out = [];
  var push = o => out.push({
    confidence: "strong",
    related: [],
    chapter: "—",
    action: "Open",
    ...o
  });

  // Quests with unfinished steps.
  for (var q of B.EntityService.listSync("quests")) {
    var steps = q.data?.steps || [];
    var open = steps.filter(s => s && s.status !== "done" && s.status !== "complete");
    if (steps.length && open.length) {
      push({
        id: "td-q-" + q.id,
        section: "quests",
        title: `${q.name}: ${open.length} step(s) open`,
        why: `${steps.length - open.length}/${steps.length} steps done.`,
        related: [{
          id: q.id,
          type: "quests",
          label: q.name
        }],
        action: "Open in Quests panel"
      });
    }
  }
  // Pending review items → things needing attention.
  var pending = (B.ReviewService?.listSync() || []).filter(r => r.status !== "done").slice(0, 6);
  for (var r of pending) {
    push({
      id: "td-r-" + r.id,
      section: "untouched",
      title: `Review: ${r.name || r.payload?.name || "candidate"}`,
      why: r.payload?.sourceQuote || r.reason || "Pending in the review queue.",
      related: r.entityId && r.entityType ? [{
        id: r.entityId,
        type: r.entityType,
        label: r.name || "entity"
      }] : [],
      action: "Open Review Queue",
      confidence: "high"
    });
  }
  // Recent chapters → writing prompts.
  var chapters = (B.ManuscriptChapterService?.loadSync()?.chapters || []).slice(-2);
  for (var c of chapters) {
    push({
      id: "td-c-" + c.id,
      section: "prompts",
      title: `Continue "${c.title || "chapter"}"`,
      why: "Pick up where the last draft left off.",
      related: [],
      action: "Open Writer's Room",
      chapter: c.title || "—"
    });
  }
  return out;
}

