// --- progress / completion ------------------------------------------
var isStepComplete = (id, data) => {
  switch (id) {
    case "welcome":
      return !!(data.welcome?.title && data.welcome?.format && data.welcome?.start);
    case "foundation":
      return !!(data.foundation?.premise && (data.foundation?.themes?.length || data.foundation?.toneWords?.length));
    case "style":
      return Object.keys(data.style?.dials || {}).length >= 4;
    case "voice":
      return !!(data.voice?.sample || data.voice?.uploaded);
    case "world":
      return (data.world?.canonRules?.length || 0) > 0 || !!data.world?.worldType;
    case "cast":
      return (data.cast?.seeds?.length || 0) > 0;
    case "rpg":
      return Object.values(data.rpg?.toggles || {}).some(Boolean) || !!data.rpg?.template;
    case "plot":
      return (data.plot?.beats?.length || 0) > 0;
    case "manuscript":
      return !!data.manuscript?.mode;
    case "references":
      return true;
    case "ai":
      return !!data.ai?.mode;
    case "review":
      return !!data.review?.queueDisplay;
    case "workspace":
      return !!data.workspace?.startTab;
    case "summary":
      return false;
    default:
      return false;
  }
};

