    var changes = shallowChangeRows(item);
    var evidence = evidenceRows(item, impact);
    var hints = consequenceHints(item, impact);
    var sourceKind = item.matchType === "inferred" || item.payload?.inference ? "inferred" : item.payload?.detector || item.matchType === "exact" ? "explicit" : "suggested";
