function wheelSlotsForContext(ctx, queueCount) {
  var kind = ctx && ctx.kind || "default";
  var review = {
    id: "review",
    icon: "bell",
    lbl: "Review",
    queue: queueCount || 0
  };
  if (kind === "selection") return [{
    id: "extract-standard",
    icon: "sparkle",
    lbl: "Extract"
  }, {
    id: "extract-deep",
    icon: "bolt",
    lbl: "Deep · AI"
  }, {
    id: "create",
    icon: "plus",
    lbl: "New entity"
  }, {
    id: "copy",
    icon: "paper",
    lbl: "Copy"
  }, review];
  if (kind === "chapter") return [{
    id: "extract-chapter-standard",
    icon: "sparkle",
    lbl: "Extract chapter"
  }, {
    id: "extract-chapter-deep",
    icon: "bolt",
    lbl: "Deep · AI"
  }, {
    id: "open-wizard",
    icon: "stack",
    lbl: "Wizard"
  }, {
    id: "create",
    icon: "plus",
    lbl: "Create"
  }, review, {
    id: "speed",
    icon: "eye",
    lbl: "Speed"
  }];
  if (kind === "entity") return [{
    id: "open-entity",
    icon: "paper",
    lbl: "Open"
  }, {
    id: "edit-entity",
    icon: "more",
    lbl: "Edit"
  }, {
    id: "merge-entity",
    icon: "link",
    lbl: "Merge"
  }, review];
  return [{
    id: "open-wizard",
    icon: "sparkle",
    lbl: "Extract"
  }, {
    id: "create",
    icon: "plus",
    lbl: "Create"
  }, {
    id: "tag",
    icon: "bookmark",
    lbl: "Tag"
  }, {
    id: "merge",
    icon: "link",
    lbl: "Merge"
  }, review, {
    id: "speed",
    icon: "eye",
    lbl: "Speed"
  }, {
    id: "tangle",
    icon: "knot",
    lbl: "Tangle",
    disabled: true,
    reason: "Coming soon"
  }, {
    id: "more",
    icon: "more",
    lbl: "More…"
  }];
}

