// Helper: shade a hex color toward black (negative) or white (positive) by amount [-1..1]
function shadeColor(hex, amt) {
  var m = hex.replace("#", "");
  var r = parseInt(m.substring(0, 2), 16);
  var g = parseInt(m.substring(2, 4), 16);
  var b = parseInt(m.substring(4, 6), 16);
  var adj = c => {
    var t = amt < 0 ? 0 : 255;
    var p = Math.abs(amt);
    return Math.round((t - c) * p + c);
  };
  var toHex = n => Math.max(0, Math.min(255, n)).toString(16).padStart(2, "0");
  return "#" + toHex(adj(r)) + toHex(adj(g)) + toHex(adj(b));
}

